#ifndef TERM4K_JSON_UTILS_H
#define TERM4K_JSON_UTILS_H

#include <map>
#include <cstddef>
#include <string>

// 轻量级 JSON 工具（扁平键值结构）
class JsonUtils {
public:
    JsonUtils() = default;

    explicit JsonUtils(std::map<std::string, std::string> values);

    // 设置键值
    void set(const std::string &key, const std::string &value);

    // 获取键值；若不存在返回 defaultValue
    std::string get(const std::string &key, const std::string &defaultValue = "") const;

    // 判断键是否存在
    bool has(const std::string &key) const;

    // 返回全部键值
    const std::map<std::string, std::string> &values() const;

    // 解析 JSON 文本（仅支持扁平字符串键值对象）
    static bool parseFlatObject(const std::string &content, JsonUtils &out);

    // 从文件加载 JSON（仅支持扁平字符串键值对象）
    static bool loadFlatObjectFromFile(const std::string &filePath, JsonUtils &out);

    // 序列化为 JSON 文本（扁平字符串键值对象）
    static std::string stringifyFlatObject(const JsonUtils &json);

private:
    static void skipWhitespace(const std::string &s, std::size_t &pos);

    static bool parseJsonString(const std::string &s, std::size_t &pos, std::string &out);

    static std::string escapeJsonString(const std::string &s);

    std::map<std::string, std::string> values_;
};

#endif // TERM4K_JSON_UTILS_H

#ifndef TERM4K_JSON_UTILS_H
#define TERM4K_JSON_UTILS_H

#include <map>
#include <cstddef>
#include <string>

// 轻量级 JSON 工具（扁平键值结构）
class JsonUtils {
public:
    JsonUtils() = default;

    explicit JsonUtils(std::map<std::string, std::string> values);

    // 设置键值
    void set(const std::string &key, const std::string &value);

    // 获取键值；若不存在返回 defaultValue
    std::string get(const std::string &key, const std::string &defaultValue = "") const;

    // 判断键是否存在
    bool has(const std::string &key) const;

    // 返回全部键值
    const std::map<std::string, std::string> &values() const;

    // 解析 JSON 文本（仅支持扁平字符串键值对象）
    static bool parseFlatObject(const std::string &content, JsonUtils &out);

    // 从文件加载 JSON（仅支持扁平字符串键值对象）
    static bool loadFlatObjectFromFile(const std::string &filePath, JsonUtils &out);

    // 序列化为 JSON 文本（扁平字符串键值对象）
    static std::string stringifyFlatObject(const JsonUtils &json);

private:
    static void skipWhitespace(const std::string &s, std::size_t &pos);

    static bool parseJsonString(const std::string &s, std::size_t &pos, std::string &out);

    static std::string escapeJsonString(const std::string &s);

    std::map<std::string, std::string> values;
};

#endif // TERM4K_JSON_UTILS_H

#include "UserStatInstance.h"

#include "services/AuthenticatedUserService.h"

#include <algorithm>
#include <cmath>

namespace {
    double normalizeAccuracy(const float accuracy) {
        if (accuracy > 1.0f) return static_cast<double>(accuracy) / 100.0;
        if (accuracy < 0.0f) return 0.0;
        return static_cast<double>(accuracy);
    }
}

bool UserStatInstance::refresh(const std::string &chartsRoot) {
    records_   = AuthenticatedUserService::loadCurrentUserVerifiedRecords(chartsRoot);
    rating_    = 0.0;
    potential_ = 0.0;

    if (records_.records.empty()) return false;

    std::vector<double> evaluations;
    evaluations.reserve(records_.records.size());
    for (const auto &key: records_.order){
        const auto it = records_.records.find(key);
        if (it == records_.records.end()) continue;
        evaluations.push_back(singleChartEvaluation(it->second.chart.getDifficulty(), it->second.accuracy));
    }

    std::sort(evaluations.begin(), evaluations.end(), std::greater<double>());
    const std::size_t b50Count = std::min<std::size_t>(50, evaluations.size());
    for (std::size_t i = 0; i < b50Count; ++i){
        rating_ += evaluations[i];
    }
    if (b50Count > 0){
        potential_ = rating_ / static_cast<double>(b50Count);
    }
    return true;
}

const ChartRecordCollection &UserStatInstance::records() const {
    return records_;
}

double UserStatInstance::rating() const {
    return rating_;
}

double UserStatInstance::potential() const {
    return potential_;
}

double UserStatInstance::singleChartEvaluation(const float difficulty, const float accuracy) {
    const double a  = normalizeAccuracy(accuracy);
    const double a2 = a * a;
    const double a4 = a2 * a2;
    return static_cast<double>(difficulty) * (a - a2 + a4);
}

#include "UserStatInstance.h"

#include "services/AuthenticatedUserService.h"

#include <algorithm>
#include <cmath>

namespace {
    double normalizeAccuracy(const float accuracy) {
        if (accuracy > 1.0f) return static_cast<double>(accuracy) / 100.0;
        if (accuracy < 0.0f) return 0.0;
        return static_cast<double>(accuracy);
    }
}

bool UserStatInstance::refresh(const std::string &chartsRoot) {
    userRecords       = AuthenticatedUserService::loadCurrentUserVerifiedRecords(chartsRoot);
    currentRating     = 0.0;
    currentPotential  = 0.0;

    if (userRecords.records.empty()) return false;

    std::vector<double> evaluations;
    evaluations.reserve(userRecords.records.size());
    for (const auto &key: userRecords.order){
        const auto it = userRecords.records.find(key);
        if (it == userRecords.records.end()) continue;
        evaluations.push_back(singleChartEvaluation(it->second.chart.getDifficulty(), it->second.accuracy));
    }

    std::sort(evaluations.begin(), evaluations.end(), std::greater<>());
    // 统计逻辑：取评价最高的前 50 首并求和/平均。
    const std::size_t b50Count = std::min<std::size_t>(50, evaluations.size());
    for (std::size_t i = 0; i < b50Count; ++i){
        currentRating += evaluations[i];
    }
    if (b50Count > 0){
        currentPotential = currentRating / static_cast<double>(b50Count);
    }
    return true;
}

const ChartRecordCollection &UserStatInstance::records() const {
    return userRecords;
}

double UserStatInstance::rating() const {
    return currentRating;
}

double UserStatInstance::potential() const {
    return currentPotential;
}

double UserStatInstance::singleChartEvaluation(const float difficulty, const float accuracy) {
    const double a  = normalizeAccuracy(accuracy);
    const double a2 = a * a;
    const double a4 = a2 * a2;
    return static_cast<double>(difficulty) * (a - a2 + a4);
}
